/**
 * Bench: Phyle temporal depth pipeline — correctness + throughput.
 */

import {
  createPhyleTemporalPipeline,
  ingestFrame,
  classifyTemporalDeblur,
  pipelineReport,
  framesAtShell,
  noiseResolvesAtShell,
  spectralBudget,
  type DepthFrame,
  type PhyleTemporalPipelineState,
} from './phyle-temporal-depth';

const WIDTH = 64;
const HEIGHT = 64;
const PIX = WIDTH * HEIGHT;

function makeFrame(fillDepth: number, noise: number, deblur: number): DepthFrame {
  const values = new Float32Array(PIX);
  const confidence = new Float32Array(PIX);
  const deblurAdmission = new Float32Array(PIX);
  for (let i = 0; i < PIX; i++) {
    values[i] = fillDepth + (Math.random() - 0.5) * noise;
    confidence[i] = 1.0 - noise;
    deblurAdmission[i] = deblur + (Math.random() - 0.5) * noise * 0.5;
  }
  return { values, confidence, deblurAdmission, width: WIDTH, height: HEIGHT, frameIndex: 0, timestamp: Date.now() };
}

// ─── Correctness tests ──────────────────────────────────────────────

console.log('=== PHYLE TEMPORAL DEPTH PIPELINE BENCH ===\n');

// Test 1: Standing wave detection (constant depth across 3 frames)
{
  const pipe = createPhyleTemporalPipeline(WIDTH, HEIGHT);
  const r1 = ingestFrame(pipe, makeFrame(0.5, 0, 0.8));
  const r2 = ingestFrame(pipe, makeFrame(0.5, 0, 0.8));
  const r3 = ingestFrame(pipe, makeFrame(0.5, 0, 0.8));
  console.log('Test 1 - Standing wave (constant depth):');
  console.log(`  Window completed: ${r3 !== null}`);
  console.log(`  Standing wave pixels: ${r3?.standingWaveCount}/${PIX} (${((r3?.standingWaveCount ?? 0) / PIX * 100).toFixed(1)}%)`);
  console.log(`  Shell: ${r3?.shell}`);
  console.log(`  Mean 2nd-degree diff: ${r3?.meanSecondDegreeDiff.toFixed(6)}`);
  console.log(`  Deblur stability: ${r3?.meanDeblurStability.toFixed(3)}`);
  console.log('');
}

// Test 2: Noise detection (random depth across 3 frames)
{
  const pipe = createPhyleTemporalPipeline(WIDTH, HEIGHT);
  ingestFrame(pipe, makeFrame(0.1, 0.8, 0.3));
  ingestFrame(pipe, makeFrame(0.9, 0.8, 0.7));
  const r3 = ingestFrame(pipe, makeFrame(0.2, 0.8, 0.1));
  console.log('Test 2 - White noise (random depth):');
  console.log(`  Standing wave: ${r3?.standingWaveCount}/${PIX}`);
  console.log(`  White deferred: ${r3?.whiteDeferred}/${PIX}`);
  console.log(`  Mean 2nd-degree diff: ${r3?.meanSecondDegreeDiff.toFixed(4)}`);
  console.log('');
}

// Test 3: Pink noise (small variance)
{
  const pipe = createPhyleTemporalPipeline(WIDTH, HEIGHT);
  ingestFrame(pipe, makeFrame(0.50, 0.01, 0.6));
  ingestFrame(pipe, makeFrame(0.51, 0.01, 0.6));
  const r3 = ingestFrame(pipe, makeFrame(0.49, 0.01, 0.6));
  console.log('Test 3 - Pink noise (small variance, resolves at shell 0):');
  console.log(`  Pink resolved: ${r3?.pinkResolved}/${PIX}`);
  console.log(`  Standing wave: ${r3?.standingWaveCount}`);
  console.log(`  Brown: ${r3?.brownResolved}`);
  console.log('');
}

// Test 4: Shell promotion (9 frames = shell 0 → shell 1)
{
  const pipe = createPhyleTemporalPipeline(WIDTH, HEIGHT);
  for (let i = 0; i < 9; i++) {
    ingestFrame(pipe, makeFrame(0.5, 0.001, 0.8));
  }
  const report = pipelineReport(pipe);
  console.log('Test 4 - Shell promotion after 9 frames:');
  console.log(`  Shell: ${report.currentShell}`);
  console.log(`  Windows completed: ${report.tritonWindowsCompleted}`);
  console.log(`  Coverage: ${(report.standingWaveCoverage * 100).toFixed(1)}%`);
  console.log(`  Frames until next shell: ${report.framesUntilNextShell}`);
  console.log('');
}

// Test 5: Temporal deblur classification
{
  const pipe = createPhyleTemporalPipeline(WIDTH, HEIGHT);
  // First half: stable deblur (real edges)
  // Second half: unstable deblur (noise artifacts)
  const frame1: DepthFrame = {
    values: new Float32Array(PIX),
    confidence: new Float32Array(PIX).fill(1),
    deblurAdmission: new Float32Array(PIX),
    width: WIDTH, height: HEIGHT, frameIndex: 0, timestamp: Date.now(),
  };
  const frame2: DepthFrame = { ...frame1, deblurAdmission: new Float32Array(PIX) };
  const frame3: DepthFrame = { ...frame1, deblurAdmission: new Float32Array(PIX) };

  for (let i = 0; i < PIX; i++) {
    frame1.values[i] = 0.5;
    frame2.values[i] = 0.5;
    frame3.values[i] = 0.5;
    if (i < PIX / 2) {
      // Stable deblur
      frame1.deblurAdmission[i] = 0.8;
      frame2.deblurAdmission[i] = 0.8;
      frame3.deblurAdmission[i] = 0.8;
    } else {
      // Unstable deblur (noise artifact)
      frame1.deblurAdmission[i] = 0.9;
      frame2.deblurAdmission[i] = 0.1;
      frame3.deblurAdmission[i] = 0.7;
    }
  }

  ingestFrame(pipe, frame1);
  ingestFrame(pipe, frame2);
  ingestFrame(pipe, frame3);

  const deblurReport = classifyTemporalDeblur(pipe);
  console.log('Test 5 - Temporal deblur classification:');
  console.log(`  Stable edges: ${deblurReport?.stableEdgeCount}/${PIX}`);
  console.log(`  Noise artifacts: ${deblurReport?.noiseArtifactCount}/${PIX}`);
  console.log('');
}

// ─── Throughput benchmark ───────────────────────────────────────────

console.log('--- THROUGHPUT ---');
{
  const FRAMES = 81; // = 3^4, enough for 27 windows (shell 2 → shell 3)
  const pipe = createPhyleTemporalPipeline(WIDTH, HEIGHT);

  const t0 = performance.now();
  for (let i = 0; i < FRAMES; i++) {
    ingestFrame(pipe, makeFrame(0.5, 0.02, 0.7));
  }
  const elapsed = performance.now() - t0;

  const report = pipelineReport(pipe);
  const perFrame = elapsed / FRAMES;
  const perWindow = elapsed / report.tritonWindowsCompleted;

  console.log(`  ${FRAMES} frames (${WIDTH}x${HEIGHT}) in ${elapsed.toFixed(1)}ms`);
  console.log(`  Per frame: ${perFrame.toFixed(2)}ms`);
  console.log(`  Per triton window: ${perWindow.toFixed(2)}ms`);
  console.log(`  Windows completed: ${report.tritonWindowsCompleted}`);
  console.log(`  Final shell: ${report.currentShell}`);
  console.log(`  Standing wave coverage: ${(report.standingWaveCoverage * 100).toFixed(1)}%`);
  console.log('');
}

