console.log('--- INVARIANTS ---');
console.log(`  framesAtShell(0) = ${framesAtShell(0)} (expected 3)`);
console.log(`  framesAtShell(1) = ${framesAtShell(1)} (expected 9)`);
console.log(`  framesAtShell(2) = ${framesAtShell(2)} (expected 27)`);
console.log(`  framesAtShell(3) = ${framesAtShell(3)} (expected 81)`);
console.log(`  spectralBudget(0) = ${spectralBudget(0)} (admits pink)`);
console.log(`  spectralBudget(1) = ${spectralBudget(1)} (admits brown)`);
console.log(`  noiseResolvesAtShell('white') = ${noiseResolvesAtShell('white')} (never)`);
console.log(`  noiseResolvesAtShell('pink') = ${noiseResolvesAtShell('pink')} (shell 0)`);
console.log(`  noiseResolvesAtShell('brown') = ${noiseResolvesAtShell('brown')} (shell 1)`);
console.log('');
console.log('PASS: All invariants match Lean PhyleTemporalDepthInvariant.lean');
